//-------------------------------------------------------------------------
// 외상매출/그외 선택시
//-------------------------------------------------------------------------
scwin.rd_select_onviewchange = function (info) {
    try{
        let rdSelect = rd_select.getValue();

        if(rdSelect == 1){
            div_grd.show("");
            div_grd2.hide();
            div_btn1.show("");
            $c.gus.cfEnableObjects([rd_std2]);
            ds_condition.set("acctCd", "");
            $c.gus.cfDisableObjects([lc_acctCd]);    
        }else {
            div_grd.hide();
            div_grd2.show("");
            div_btn1.hide();
            rd_std.setValue(1); //rd_std[0].checked = true;
            rd_std2.setValue(0);
            $c.gus.cfDisableObjects([rd_std2]);
            $c.gus.cfEnableObjects([lc_acctCd]);
        }

    }catch (e){
        console.log("rd_select_onviewchange : " +e);
    }
};

